def equalFrequency(self, word: str) -> bool:
    freq_dict = {}
    for char in word:
        if char in freq_dict:
            freq_dict[char] += 1
        else:
            freq_dict[char] = 1
    for char in word:
        if freq_dict[char] > 1:
            return False
    return True

